	if requested != nil {
		return *requested
	}
	s := os.Getenv("DEFAULT_PAGE_SIZE")
	if s != "" {
		if n, err := strconv.Atoi(s); err == nil && n > 0 {
			return n
		}
	}
	return 20
}

